// // This module implements a 16-bit shift register that shifts left on a rising edge of the clock, loads parallel input data 'd' on a falling edge of the clock when the 'load' input is high, and shifts in 'si' when 'load' is low.
module top_module(
    input wire clk,
    input wire reset,
    input wire load,
    input wire [15:0] d,
    input wire si,
    output reg [15:0] q
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 16'b0000000000000000;
        end else if (load) begin
            q <= d;
        end else begin
            q <= {si, q[15:1]};
        end
    end

endmodule
